targets.expr:
100 * (
  sum by (kube_deployment_name, kube_namespace_name) (
    rate(http_server_request_duration_count{http_response_status_code=~"2..|3..", kube_deployment_name="$application", kube_namespace_name="$namespace"}[$__rate_interval])
  )
  /
  sum by (kube_deployment_name, kube_namespace_name) (
    rate(http_server_request_duration_count{kube_deployment_name="$application", kube_namespace_name="$namespace"}[$__rate_interval])
  )
)

sum by (kube_deployment_name) (
  max_over_time(
    db_client_connection_count{
      db_client_connection_state="used",
      kube_deployment_name="$application",
      kube_namespace_name="$namespace"
    }[$__interval]
  )
)

sum by (http_request_method, http_route) (
  rate(
    http_server_request_duration_count{
      kube_deployment_name=~"$application",
      kube_namespace_name="$namespace"
    }[$__rate_interval]
  )
)

sum by (http_request_method, http_route) (
  increase(
    http_server_request_duration_sum{ kube_deployment_name=~"$application", kube_namespace_name="$namespace" }[$__range]
  )
)
/
scalar(
  sum(
    increase(
      http_server_request_duration_sum{ kube_deployment_name=~"$application", kube_namespace_name="$namespace" }[$__range]
    )
  )
)
* 100 > 0

sum by (http_request_method, http_route) (
  rate(
    http_server_request_duration_count{
      kube_deployment_name=~"$application",
      kube_namespace_name="$namespace",
      http_route!="/api/v1/jobs/:id"
    }[$__rate_interval]
  )
)

sum by (http_request_method, http_route) (
  increase(
    http_server_request_duration_sum{ kube_deployment_name=~"$application", kube_namespace_name="$namespace", http_route!="/api/v1/jobs/:id" }[$__range]
  )
)
/
scalar(
  sum(
    increase(
      http_server_request_duration_sum{ kube_deployment_name=~"$application", kube_namespace_name="$namespace", http_route!="/api/v1/jobs/:id" }[$__range]
    )
  )
)
* 100 > 0

histogram_quantile(
  0.75,
  sum by (method_route, le) (
    label_join(
      rate(http_server_request_duration_bucket{kube_deployment_name="$application", kube_namespace_name="$namespace", http_response_status_code=~"2..|3.."}[$__rate_interval]),
      "method_route", " ",
      "http_request_method", "http_route"
    )
  )
)

histogram_quantile(
  0.95,
  sum by (method_route, le) (
    label_join(
      rate(http_server_request_duration_bucket{kube_deployment_name="$application", kube_namespace_name="$namespace", http_response_status_code=~"2..|3.."}[$__rate_interval]),
      "method_route", " ",
      "http_request_method", "http_route"
    )
  )
)

histogram_quantile(
