  10,
  histogram_quantile(
    0.99,
    sum by (http_request_method, http_route, le) (
      rate(http_server_request_duration_bucket{kube_deployment_name=~"$application", kube_namespace_name="$namespace"}[$__rate_interval])
    )
  )
)

sum by (auth) (
  rate(
    http_request_auth_status_total{ kube_deployment_name=~"$application", kube_namespace_name="$namespace" }[$__rate_interval]
